#include <iostream>
#include <vector>
#include <string>
using namespace std;

string buildLargeString() {
    string s = "Hello, C++ World! ";
    for (int i = 0; i < 3; i++) s += s;  // grow it
    return s;  // Return Value Optimization (RVO) kicks in
}

int main() {
    vector<int> original = {1, 2, 3, 4, 5};
    cout << "Original size: " << original.size() << endl;

    vector<int> moved = move(original);  // O(1) move!
    cout << "Moved size: "    << moved.size()    << endl;
    cout << "Original after move: " << original.size() << endl;  // 0!

    // String move:
    string s1 = buildLargeString();
    cout << "s1 length: " << s1.length() << endl;
    string s2 = move(s1);  // s2 takes ownership, s1 becomes empty
    cout << "s1 after move: '" << s1 << "'" << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>
#include <string>
using namespace std;

int main() {
    // Saves typing:
    auto pi = 3.14159;
    auto msg = string("Hello");

    // Essential for iterators:
    map<string, vector<int>> data;
    data["scores"] = {90, 85, 92};

    // Without auto: map<string, vector<int>>::iterator it = data.begin();
    auto it = data.begin();  // much cleaner!
    cout << it->first << ": " << it->second.size() << " scores" << endl;

    // auto in range-based for:
    for (const auto& [key, values] : data) {
        cout << key << ": ";
        for (auto v : values) cout << v << " ";
        cout << endl;
    }

    return 0;
}

#include <iostream>
#include <map>
#include <tuple>
#include <string>
using namespace std;

struct RGB { int r, g, b; };

tuple<string, int, double> getUser() {
    return {"Alice", 30, 9.5};
}

int main() {
    // Unpack tuple:
    auto [name, age, rating] = getUser();
    cout << name << ", " << age << ", " << rating << endl;

    // Unpack map entries:
    map<string, int> scores = {{"Alice", 90}, {"Bob", 85}};
    for (const auto& [student, score] : scores) {
        cout << student << ": " << score << endl;
    }

    // Unpack struct:
    RGB color = {255, 128, 0};
    auto [r, g, b] = color;
    cout << "R=" << r << " G=" << g << " B=" << b << endl;

    return 0;
}

