#include <iostream>
#include <optional>
#include <vector>
#include <string>
using namespace std;

optional<int> findValue(const vector<int>& v, int target) {
    for (int i = 0; i < (int)v.size(); i++) {
        if (v[i] == target) return i;  // return the index
    }
    return nullopt;  // not found
}

optional<string> getUser(int id) {
    if (id == 1) return "Alice";
    if (id == 2) return "Bob";
    return nullopt;
}

int main() {
    vector<int> nums = {5, 3, 9, 1, 7};

    auto idx = findValue(nums, 9);
    if (idx) cout << "Found at index: " << *idx << endl;

    auto notFound = findValue(nums, 42);
    cout << "Value or -1: " << notFound.value_or(-1) << endl;

    for (int id : {1, 2, 3}) {
        auto user = getUser(id);
        cout << id << ": " << user.value_or("(not found)") << endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <map>
using namespace std;

struct Config {
    string host;
    int port;
    bool ssl;
};

void printVec(initializer_list<int> items) {
    for (int item : items) cout << item << " ";
    cout << endl;
}

int main() {
    // Uniform initialization:
    int x{42};
    double d{3.14};
    Config cfg{"localhost", 8080, false};

    cout << cfg.host << ":" << cfg.port << endl;

    // Initializer list:
    printVec({1, 2, 3, 4, 5});
    printVec({10, 20, 30});

    // vector with initializer list:
    vector<int> v{5, 3, 1, 4, 2};
    for (int n : v) cout << n << " ";
    cout << endl;

    return 0;
}
